// En n8n el body del webhook llega bajo .body
const raw  = $input.first().json;
const body = raw.body || raw; // fallback si ya viene sin wrapper

const data = body.data    || {};
const key  = data.key     || {};
const msg  = data.message || {};

// Ignorar mensajes propios
if (key.fromMe === true) return [];

// Número remoto (key.remoteJid tiene prioridad, sender como fallback)
const remoteJid = key.remoteJid || body.sender || '';

// Ignorar grupos y vacíos
if (!remoteJid || remoteJid.includes('@g.us')) return [];

// Solo texto plano o texto extendido
const tipo = data.messageType || '';
if (!['conversation', 'extendedTextMessage'].includes(tipo)) return [];

const texto = msg.conversation || msg.extendedTextMessage?.text || '';
if (!texto.trim()) return [];

const numero = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

return [{
  json: {
    numero,
    texto: texto.trim(),
    nombre: data.pushName || 'Cliente',
    sessionId: `barberia_${numero}`
  }
}];
